import{_ as a,o as t,c as o,a5 as r}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：三相 dq 电流环解耦","description":"","frontmatter":{"date":"2026-06-22T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：三相 dq 电流环解耦","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0039-three-phase-current-loop-decoupling.html` 的源稿。"},"headers":[],"relativePath":"content/power/concepts/control/three-phase-current-loop-decoupling.md","filePath":"content/power/concepts/control/three-phase-current-loop-decoupling.md","lastUpdated":null}'),i={name:"content/power/concepts/control/three-phase-current-loop-decoupling.md"};function n(l,e,s,c,p,d){return t(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="概念-三相-dq-电流环解耦" tabindex="-1">概念：三相 dq 电流环解耦 <a class="header-anchor" href="#概念-三相-dq-电流环解耦" aria-label="Permalink to &quot;概念：三相 dq 电流环解耦&quot;">​</a></h1><p>本页是 <code>lessons/0039-three-phase-current-loop-decoupling.html</code> 的源稿。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>dq 电流环解耦（dq current loop decoupling）用前馈项抵消旋转坐标系中的交叉耦合，让 id 和 iq 更接近两个独立控制对象。</p><h2 id="为什么-ups-pcs-需要它" tabindex="-1">为什么 UPS/PCS 需要它 <a class="header-anchor" href="#为什么-ups-pcs-需要它" aria-label="Permalink to &quot;为什么 UPS/PCS 需要它&quot;">​</a></h2><p>Vienna PFC、三相逆变器和 PCS 并网电流控制都需要快速、可解释的电流环。无解耦时 id 阶跃会扰动 iq。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vd_ref = PI(id_ref - id) - omega * L * iq + ed</span></span>
<span class="line"><span>vq_ref = PI(iq_ref - iq) + omega * L * id + eq</span></span></code></pre></div><h2 id="一个仿真任务" tabindex="-1">一个仿真任务 <a class="header-anchor" href="#一个仿真任务" aria-label="Permalink to &quot;一个仿真任务&quot;">​</a></h2><p>让 id_ref 阶跃、iq_ref 保持 0，对比有无解耦时 iq 的暂态扰动。</p><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能解释 omega * L * i 的来源。</li><li>能说明解耦项符号必须和 Park 变换定义一致。</li><li>能区分解耦、前馈、限幅和 PI 的职责。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><p>阅读真实代码时，如何确认电流环 PI、解耦、前馈和限幅的执行顺序？</p>`,14)])])}const q=a(i,[["render",n]]);export{u as __pageData,q as default};
